package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetDelimiter() throws Exception {
        // Given
        char expectedDelimiter = ',';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        char actualDelimiter = csvFormat.getDelimiter();

        // Then
        assertEquals(expectedDelimiter, actualDelimiter);
    }

    @Test
    public void testGetDelimiter_CustomDelimiter() throws Exception {
        // Given
        char expectedDelimiter = '|';
        CSVFormat csvFormat = new CSVFormat('|', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);

        // When
        char actualDelimiter = csvFormat.getDelimiter();

        // Then
        assertEquals(expectedDelimiter, actualDelimiter);
    }

    @Test
    public void testGetDelimiter_UsingMockito() throws Exception {
        // Given
        char expectedDelimiter = '\t';
        CSVFormat csvFormat = mock(CSVFormat.class);
        when(csvFormat.getDelimiter()).thenReturn('\t');

        // When
        char actualDelimiter = csvFormat.getDelimiter();

        // Then
        assertEquals(expectedDelimiter, actualDelimiter);
    }
}
